INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Medicine Ball Front Rack Breathing Squat', 'medicine-ball-front-rack-breathing-squat', 'Hold the medicine ball at the chest, breathe into the brace, and squat through a controlled range without throwing.', 'BEGINNER', 8, 2, 6, NULL, 30, 30, 'Medicine Ball Front Rack Breathing Squat trains front-rack squat access with calm breathing before wall-ball work. It belongs in Prepare And Access when the coach wants foundation, position, and skill ownership without losing wall-ball mechanics.', 'Primary subrole: activate. Belongs in Prepare & Access because the drill improves readiness, access, activation, or position ownership before higher-intent work without creating meaningful fatigue. Coach wall-ball work by phase intent: skill reps stay crisp, power reps stay fresh, support drills stay controlled, and conditioning stops when quality drops.', 'Brace first, then squat.', 'Wall-ball squat access', 'prepare_and_access', 'activate', 'wall_ball_front_rack_breathing_squat', '{"primary_joint_actions":["front-rack bracing","front-rack catch","overhead reach","squat","triple extension"],"primary_tissues":["anterior core","calves","glutes","quadriceps","shoulders","triceps"],"primary_motor_control_demands":[],"postural_shape":"front_rack_athletic_base","breathing_demand":"low-to-moderate","balance_demand":"low-to-moderate","coordination_demand":"moderate","impact_level":0,"expression_quality":null,"contraindication_flags":[]}'::jsonb, '{"movement_description":"Hold the medicine ball at the chest, breathe into the brace, and squat through a controlled range without throwing.","setup":["Choose a medicine-ball weight that the athlete can catch without bracing through the face, neck, or low back.","Use a clear wall target, safe wall surface, non-slip floor, and enough space so misses do not strike another athlete.","Start with feet under the hips or in the stance required by the card, ball held high at the chest unless the variation says otherwise."],"execution_steps":["Organize the ribs over the pelvis, grip the ball securely, and establish the target or movement lane before the rep begins.","Hold the medicine ball at the chest, breathe into the brace, and squat through a controlled range without throwing.","Finish each rep with the ball, feet, trunk, and eyes controlled before starting the next rep.","End the set as soon as catch quality, squat depth, target accuracy, breathing rhythm, or spacing breaks down."],"coach_cues":["Ball high at the chest.","Ribs stacked over hips.","Drive the floor away.","Throw through the target.","Catch soft and reset."],"breathing_cues":["Inhale or reset breath as the ball returns or before the descent.","Exhale through the drive and throw without losing trunk position.","During intervals, use small planned breaths between reps rather than holding breath across the set."],"quality_gate":"Rep counts only when squat position, target accuracy, ball path, catch safety, and breathing remain repeatable.","stop_signs":["Shoulder, wrist, back, hip, knee, ankle, neck, or pelvic-floor symptoms.","Repeated missed targets, face-level catches, dropped balls, or uncontrolled rebounds.","Knees collapse, heels consistently lift, trunk folds, or the athlete cannot reset breathing.","Crowded lane, unsafe wall surface, or ball weight too heavy to receive safely."],"common_faults":["Letting the ball pull the chest and eyes down during the catch.","Throwing from the low back instead of extending through legs, trunk, and arms together.","Choosing a ball that is too heavy or a target that is too high for clean rhythm.","Turning a skill or power drill into conditioning by rushing the next rep."],"regressions":[],"progressions":[]}'::jsonb),
  ('Wall Ball Target Tap', 'wall-ball-target-tap', 'Stand at wall-ball distance, extend the ball toward the target, and rehearse release height, eye line, and finish position without a hard throw.', 'INTERMEDIATE', 8, 2, 8, NULL, 30, 40, 'Wall Ball Target Tap trains target awareness and overhead reach without high force or fatigue. It belongs in Movement Intelligence when the coach wants foundation, position, and skill ownership without losing wall-ball mechanics.', 'Primary subrole: shape_position_intelligence. Belongs in Movement Intelligence because the main adaptation is coordination, timing, target recognition, spacing, and movement quality while the nervous system is fresh. Coach wall-ball work by phase intent: skill reps stay crisp, power reps stay fresh, support drills stay controlled, and conditioning stops when quality drops.', 'Show the target early.', 'Target and release prep', 'movement_intelligence', 'shape_position_intelligence', 'wall_ball_target_tap', '{"primary_joint_actions":["front-rack catch","overhead reach","squat","triple extension"],"primary_tissues":["anterior core","calves","glutes","quadriceps","shoulders","triceps"],"primary_motor_control_demands":[],"postural_shape":"front_rack_athletic_base","breathing_demand":"low-to-moderate","balance_demand":"low-to-moderate","coordination_demand":"high","impact_level":0,"expression_quality":null,"contraindication_flags":[]}'::jsonb, '{"movement_description":"Stand at wall-ball distance, extend the ball toward the target, and rehearse release height, eye line, and finish position without a hard throw.","setup":["Choose a medicine-ball weight that the athlete can catch without bracing through the face, neck, or low back.","Use a clear wall target, safe wall surface, non-slip floor, and enough space so misses do not strike another athlete.","Start with feet under the hips or in the stance required by the card, ball held high at the chest unless the variation says otherwise."],"execution_steps":["Organize the ribs over the pelvis, grip the ball securely, and establish the target or movement lane before the rep begins.","Stand at wall-ball distance, extend the ball toward the target, and rehearse release height, eye line, and finish position without a hard throw.","Finish each rep with the ball, feet, trunk, and eyes controlled before starting the next rep.","End the set as soon as catch quality, squat depth, target accuracy, breathing rhythm, or spacing breaks down."],"coach_cues":["Ball high at the chest.","Ribs stacked over hips.","Drive the floor away.","Throw through the target.","Catch soft and reset."],"breathing_cues":["Inhale or reset breath as the ball returns or before the descent.","Exhale through the drive and throw without losing trunk position.","During intervals, use small planned breaths between reps rather than holding breath across the set."],"quality_gate":"Rep counts only when squat position, target accuracy, ball path, catch safety, and breathing remain repeatable.","stop_signs":["Shoulder, wrist, back, hip, knee, ankle, neck, or pelvic-floor symptoms.","Repeated missed targets, face-level catches, dropped balls, or uncontrolled rebounds.","Knees collapse, heels consistently lift, trunk folds, or the athlete cannot reset breathing.","Crowded lane, unsafe wall surface, or ball weight too heavy to receive safely."],"common_faults":["Letting the ball pull the chest and eyes down during the catch.","Throwing from the low back instead of extending through legs, trunk, and arms together.","Choosing a ball that is too heavy or a target that is too high for clean rhythm.","Turning a skill or power drill into conditioning by rushing the next rep."],"regressions":[],"progressions":[]}'::jsonb),
  ('Wall Ball Squat-to-Press Pattern', 'wall-ball-squat-to-press-pattern', 'Squat with the ball in the front rack, stand tall, and press to the target line without releasing unless the coach approves the rhythm.', 'INTERMEDIATE', 8, 2, 6, NULL, 45, 30, 'Wall Ball Squat-to-Press Pattern trains pattern squat depth, trunk stack, and finish timing before releasing the ball. It belongs in Movement Intelligence when the coach wants foundation, position, and skill ownership without losing wall-ball mechanics.', 'Primary subrole: shape_position_intelligence. Belongs in Movement Intelligence because the main adaptation is coordination, timing, target recognition, spacing, and movement quality while the nervous system is fresh. Coach wall-ball work by phase intent: skill reps stay crisp, power reps stay fresh, support drills stay controlled, and conditioning stops when quality drops.', 'Legs finish the throw.', 'Squat-to-throw patterning', 'movement_intelligence', 'shape_position_intelligence', 'wall_ball_squat_to_press_pattern', '{"primary_joint_actions":["front-rack catch","overhead reach","squat","triple extension"],"primary_tissues":["anterior core","calves","glutes","quadriceps","shoulders","triceps"],"primary_motor_control_demands":[],"postural_shape":"front_rack_athletic_base","breathing_demand":"low-to-moderate","balance_demand":"low-to-moderate","coordination_demand":"high","impact_level":0,"expression_quality":null,"contraindication_flags":[]}'::jsonb, '{"movement_description":"Squat with the ball in the front rack, stand tall, and press to the target line without releasing unless the coach approves the rhythm.","setup":["Choose a medicine-ball weight that the athlete can catch without bracing through the face, neck, or low back.","Use a clear wall target, safe wall surface, non-slip floor, and enough space so misses do not strike another athlete.","Start with feet under the hips or in the stance required by the card, ball held high at the chest unless the variation