  ('medicine-ball-clean-to-squat', 'movement_intelligence', 'medicine_ball_clean_to_squat', 5, TRUE, 4, 2, 4, 0, 'moderate'),
  ('medicine-ball-squat-clean-to-wall-ball-shot', 'sustained_capacity', 'medicine_ball_squat_clean_to_wall_ball_shot', 5, FALSE, 4, 5, 3, 1, 'high'),
